    const N = s.length;
    let C0 = 0;
    let C1 = 0;

    for (let i = 0; i < N; i++) {
        if (s[i] === '0') {
            C0++;
        } else {
            C1++;
        }
    }

    // If the string is already monochromatic, it is coherent, cost is 0.
    if (C0 === 0 || C1 === 0) {
        return 0;
    }

    // Based on analysis, the minimum cost is achieved by transforming the string
    // into a form that has at most one '0' or at most one '1'.

    // 1. Target N0 = 1 (One zero, N-1 ones): 
    // Minimum cost to achieve this is C0 - 1, by preserving an existing '0'.
